// MARK: - TerminalSessionTests
// Only lifecycle state is tested here; PTY I/O requires a real device
// and belongs in integration tests.

struct TerminalSessionTests {

    @Test func terminalSessionInitialStateIsIdle() async {
        let session = TerminalSession()
        let state = await session.state
        if case .idle = state { } else {
            Issue.record("Expected .idle initial state, got \(state)")
        }
    }

    @Test func terminalSessionSendThrowsWhenIdle() async {
        let session = TerminalSession()
        var didThrow = false
        do {
            try await session.send(Data("hello".utf8))
        } catch {
            didThrow = true
        }
        #expect(didThrow)
    }
}

// MARK: - TerminalSessionLifecycleTests
// Integration tests that launch a real /bin/zsh over a real PTY. They cover the
// EOF-driven stream teardown (ISS-070) and the SIGKILL escalation path (ISS-072)
// added in plan 7a. Each is bounded by a timeout so a regression hangs the test
// (and fails) rather than the whole suite.

private func withTimeout<T: Sendable>(
    seconds: Double,
    _ operation: @escaping @Sendable () async -> T
) async -> T? {
    await withTaskGroup(of: T?.self) { group in
        group.addTask { await operation() }
        group.addTask {
            try? await Task.sleep(nanoseconds: UInt64(seconds * 1_000_000_000))
            return nil
        }
        let result = await group.next() ?? nil
        group.cancelAll()
        return result
    }
}

struct TerminalSessionLifecycleTests {

    /// When the shell exits, the parent's slave copy is already closed, so the
    /// master sees EOF and the output stream finishes on its own (ISS-070). A
    /// regression (slave kept open) leaves the stream open and this times out.
    @Test func sessionStreamFinishesWhenShellExits() async throws {
        let session = TerminalSession()
        try await session.start()

        // Ask the shell to exit, then confirm the stream completes.
        try await session.send(Data("exit\n".utf8))

        let stream = await session.outputStream
        let finished = await withTimeout(seconds: 6) {
            for await _ in stream { }
            return true
        }
        #expect(finished == true)

        let state = await session.state
        if case .exited = state { } else if case .idle = state {
            Issue.record("Session unexpectedly idle after shell exit")
        } else if case .running = state {
            Issue.record("Session still running after shell exit")
        }
    }

    /// A shell that traps SIGTERM must still die: `terminate()` escalates to
    /// SIGKILL after its poll window (ISS-072). A regression (no escalation) hangs
    /// the shell and `terminate()` would block past the timeout.
    @Test func terminateEscalatesToKillForTrappingShell() async throws {
        let session = TerminalSession()
        try await session.start()

        // Ignore SIGTERM and block, so only SIGKILL can stop it.
        try await session.send(Data("trap '' TERM\nsleep 60\n".utf8))
        try? await Task.sleep(nanoseconds: 600_000_000)  // let the trap install

        let completed = await withTimeout(seconds: 6) {
            await session.terminate()
            return true
        }
        #expect(completed == true)

        // After teardown the channel is gone, so sends fail.
        var didThrow = false
        do { try await session.send(Data("x".utf8)) } catch { didThrow = true }
        #expect(didThrow)
    }

    /// `terminate()` is safe to call repeatedly and on an already-dead session.
    @Test func terminateIsIdempotent() async throws {
        let session = TerminalSession()
        try await session.start()
        let first = await withTimeout(seconds: 5) { await session.terminate(); return true }
        let second = await withTimeout(seconds: 5) { await session.terminate(); return true }
        #expect(first == true)
        #expect(second == true)
    }
}

// MARK: - PTYSpawn / controlling-terminal tests (plan 7b)
// These verify that the posix_spawn launch gives Zsh a controlling terminal so
// SIGINT (Ctrl-C) reaches the foreground process group (ISS-071) — the behaviour
// Foundation.Process could not provide.

/// Thread-safe accumulator for streamed shell output.
private actor OutputAccumulator {
    private var text = ""
    func append(_ chunk: String) { text += chunk }
    func contains(_ needle: String) -> Bool { text.contains(needle) }
}

struct PTYSpawnTests {

    @Test func exitCodeDecodesNormalExit() {
        // status 0 → exit 0; high byte holds the code for a normal exit.
        #expect(PTYSpawn.exitCode(fromWaitStatus: 0) == 0)
        #expect(PTYSpawn.exitCode(fromWaitStatus: 42 << 8) == 42)
    }

    @Test func exitCodeDecodesSignalTermination() {
        // Low 7 bits hold the terminating signal; convention is 128 + signal.
        #expect(PTYSpawn.exitCode(fromWaitStatus: SIGKILL) == 128 + SIGKILL)
    }

    /// Ctrl-C must interrupt a foreground `sleep` so the prompt returns and a
    /// follow-up command runs. The marker `DONE` only appears in the command's
    /// *output* — the echoed input line reads `echo DON''E`, which never contains
    /// the contiguous substring — so a match proves the echo actually executed.
    /// Without a controlling terminal the SIGINT is lost, `sleep 100` blocks, and
    /// this times out (ISS-071).
    @Test func ctrlCInterruptsForegroundCommand() async throws {
        let session = TerminalSession()
        try await session.start()
        let stream = await session.outputStream

        let accumulator = OutputAccumulator()
        let drain = Task {
            for await data in stream {
                if let text = String(data: data, encoding: .utf8) {
                    await accumulator.append(text)
                }
            }
        }
        defer { drain.cancel() }

        // Let the login shell finish loading before issuing commands.
        try? await Task.sleep(nanoseconds: 1_200_000_000)
        try await session.send(Data("sleep 100\n".utf8))
        try? await Task.sleep(nanoseconds: 800_000_000)   // let sleep reach the foreground
        try await session.send(Data([0x03]))              // Ctrl-C → SIGINT
        try await session.send(Data("echo DON''E\n".utf8))

        let interrupted = await withTimeout(seconds: 10) {
            while !Task.isCancelled {
                if await accumulator.contains("DONE") { return true }
                try? await Task.sleep(nanoseconds: 100_000_000)
            }
            return false
        }
        #expect(interrupted == true)

        await session.terminate()
    }
}

// MARK: - IncrementalLineDecoderTests (plan 7c, ISS-079)
// The observer line splitter must carry a partial multi-byte UTF-8 code point and a
// partial line across reads, so output split on arbitrary byte boundaries never drops
// characters or whole lines (the bug ISS-079 describes).

struct IncrementalLineDecoderTests {

    // MARK: incompleteTrailingByteCount

    @Test func decoderTreatsPureASCIIAsComplete() {
        let bytes = Array("hello".utf8)
        #expect(IncrementalLineDecoder.incompleteTrailingByteCount(bytes) == 0)
    }

    @Test func decoderHoldsLoneTwoByteLead() {
        // 0xC3 is the lead byte of 'é' (C3 A9); alone it is incomplete.
        #expect(IncrementalLineDecoder.incompleteTrailingByteCount([0xC3]) == 1)
    }

    @Test func decoderCompletesTwoByteSequence() {
        // Full 'é' — nothing to hold back.
        #expect(IncrementalLineDecoder.incompleteTrailingByteCount([0xC3, 0xA9]) == 0)
    }

    @Test func decoderHoldsPartialFourByteEmoji() {
        // '😀' is F0 9F 98 80; with only three of four bytes, hold all three.
        #expect(IncrementalLineDecoder.incompleteTrailingByteCount([0xF0, 0x9F, 0x98]) == 3)
    }

    @Test func decoderCompletesFourByteEmoji() {
        #expect(IncrementalLineDecoder.incompleteTrailingByteCount([0xF0, 0x9F, 0x98, 0x80]) == 0)
    }

    @Test func decoderHoldsOnlyTrailingPartialAfterCompleteCharacter() {
        // 'A' (complete) followed by a lone two-byte lead — hold just the last byte.
        #expect(IncrementalLineDecoder.incompleteTrailingByteCount([0x41, 0xC3]) == 1)
    }

    // MARK: feed / flush

    @Test func decoderEmitsLineOnNewline() {
        var decoder = IncrementalLineDecoder()
        let lines = decoder.feed(Data("hello\n".utf8))
        #expect(lines == ["hello"])
    }

    @Test func decoderHoldsLineUntilNewlineArrives() {
        var decoder = IncrementalLineDecoder()
        #expect(decoder.feed(Data("par".utf8)).isEmpty)
        let lines = decoder.feed(Data("tial\n".utf8))
        #expect(lines == ["partial"])
    }

    @Test func decoderReassemblesUTF8SplitAcrossReads() {
        // 'café\n' with the 'é' (C3 A9) split: first read ends mid-character.
        let full = Array("café\n".utf8)
        let splitAt = full.count - 2  // between C3 and A9
        var decoder = IncrementalLineDecoder()
        let first = decoder.feed(Data(full[0..<splitAt]))
        #expect(first.isEmpty)  // incomplete code point → no line yet
        let second = decoder.feed(Data(full[splitAt...]))
        #expect(second == ["café"])
    }

    @Test func decoderReassemblesEmojiSplitAcrossThreeReads() {
        let full = Array("hi 😀\n".utf8)  // emoji is 4 bytes
        var decoder = IncrementalLineDecoder()
        var out: [String] = []
        // Feed one byte at a time — the worst-case fragmentation.
        for byte in full { out += decoder.feed(Data([byte])) }
        #expect(out == ["hi 😀"])
    }

    @Test func decoderEmitsMultipleLinesInOneChunk() {
        var decoder = IncrementalLineDecoder()
        let lines = decoder.feed(Data("a\nb\nc\n".utf8))
        #expect(lines == ["a", "b", "c"])
    }

    @Test func decoderFlushReturnsTrailingPartialLine() {
        var decoder = IncrementalLineDecoder()
        _ = decoder.feed(Data("no newline".utf8))
        #expect(decoder.flush() == "no newline")
    }

    @Test func decoderFlushReturnsNilWhenNothingHeld() {
        var decoder = IncrementalLineDecoder()
        _ = decoder.feed(Data("line\n".utf8))
        #expect(decoder.flush() == nil)
    }

    @Test func decoderTrimsControlCharactersFromLines() {
        var decoder = IncrementalLineDecoder()
        // Carriage return before the newline should be trimmed off.
        let lines = decoder.feed(Data("text\r\n".utf8))
        #expect(lines == ["text"])
    }
}

// MARK: - ZDOTDIRShimTests (ISS-077)
// The shim is shell-script-in-a-string — the highest-risk surface. These pure tests
// pin the exact emitted scripts: that each file re-sources the user's real dotfile,
// re-points ZDOTDIR correctly, and that the OSC 133 hooks land ONLY in `.zshrc`
// (after the user's config, so a precmd_functions=(...) reset cannot drop them).

struct ZDOTDIRShimTests {

    @Test func eachShimSourcesItsRealCounterpart() {
        let c = ZDOTDIRShim.contents()
        #expect(c.zshenv.contains(#"source "$real/.zshenv""#))
        #expect(c.zprofile.contains(#"source "$real/.zprofile""#))
        #expect(c.zshrc.contains(#"source "$real/.zshrc""#))
        #expect(c.zlogin.contains(#"source "$real/.zlogin""#))
    }

    @Test func everyShimRestoresRealZDOTDIRBeforeSourcing() {
        // `real` is seeded from SPUTNIK_USER_ZDOTDIR (default $HOME) and ZDOTDIR is
        // set to it before the real file is sourced, so the user's config sees the
        // correct $ZDOTDIR.
        for body in [ZDOTDIRShim.contents().zshenv,
                     ZDOTDIRShim.contents().zprofile,
                     ZDOTDIRShim.contents().zshrc,
                     ZDOTDIRShim.contents().zlogin] {
            #expect(body.contains(#"local real="${SPUTNIK_USER_ZDOTDIR:-$HOME}""#))
            #expect(body.contains(#"ZDOTDIR="$real""#))
        }
    }

    @Test func nonTerminalShimsChainBackToShimDir() {
        // .zshenv and .zprofile must hand control back to the shim dir so the next
        // shim file still runs.
        let c = ZDOTDIRShim.contents()
        #expect(c.zshenv.contains("ZDOTDIR=\"${\(ZDOTDIRShim.shimDirVar):?"))
        #expect(c.zprofile.contains("ZDOTDIR=\"${\(ZDOTDIRShim.shimDirVar):?"))
    }

    @Test func terminalShimsRestoreUserZDOTDIRPermanently() {
        // .zshrc and .zlogin leave ZDOTDIR at the user's value for good.
        let c = ZDOTDIRShim.contents()
        #expect(c.zshrc.contains("ZDOTDIR=\"$\(ZDOTDIRShim.userZDOTDIRVar)\""))
        #expect(c.zlogin.contains("ZDOTDIR=\"$\(ZDOTDIRShim.userZDOTDIRVar)\""))
        // ...and they do NOT chain back to the shim dir.
        #expect(!c.zshrc.contains(ZDOTDIRShim.shimDirVar))
        #expect(!c.zlogin.contains(ZDOTDIRShim.shimDirVar))
    }

    @Test func everyShimRecapturesUserRelocatedZDOTDIR() {
        // After sourcing, a user file may have reset ZDOTDIR; the shim re-captures it
        // so the relocation is honoured for later files (and the final value).
        for body in [ZDOTDIRShim.contents().zshenv,
                     ZDOTDIRShim.contents().zprofile,
                     ZDOTDIRShim.contents().zshrc,
                     ZDOTDIRShim.contents().zlogin] {
            #expect(body.contains(#"SPUTNIK_USER_ZDOTDIR="${ZDOTDIR:-$real}""#))
        }
    }

    @Test func osc133HooksAppearOnlyInZshrc() {
        let c = ZDOTDIRShim.contents()
        #expect(c.zshrc.contains("precmd_functions+=(__sputnik_precmd)"))
        #expect(c.zshrc.contains("preexec_functions+=(__sputnik_preexec)"))
        #expect(!c.zshenv.contains("__sputnik_precmd"))
        #expect(!c.zprofile.contains("__sputnik_precmd"))
        #expect(!c.zlogin.contains("__sputnik_precmd"))
    }

    @Test func hooksAreAppendedAfterTheUserConfigSource() {
        // The append must come AFTER `source "$real/.zshrc"` so a wholesale
        // precmd_functions=(...) reset in the user's config cannot drop our hook.
        let body = ZDOTDIRShim.contents().zshrc
        guard let sourceRange = body.range(of: #"source "$real/.zshrc""#),
              let hookRange = body.range(of: "precmd_functions+=(__sputnik_precmd)") else {
            Issue.record("Expected both the source line and the hook append in .zshrc")
            return
        }
        #expect(sourceRange.lowerBound < hookRange.lowerBound)
    }

    @Test func hooksEmitTheFourOSC133Markers() {
        // The literal escape/bell bytes must be present so the emitted printf writes
        // real OSC 133 sequences (A/B/C/D).
        let hooks = ZDOTDIRShim.osc133Hooks
        #expect(hooks.contains(#"\033]133;A\007"#))
        #expect(hooks.contains(#"\033]133;B\007"#))
        #expect(hooks.contains(#"\033]133;C\007"#))
        #expect(hooks.contains(#"\033]133;D;%s\007"#))
    }

    @Test func installWritesAllFourFilesWithRestrictivePermissions() throws {
        let dir = try ZDOTDIRShim.install()
        defer { try? FileManager.default.removeItem(at: dir) }

        for name in [".zshenv", ".zprofile", ".zshrc", ".zlogin"] {
            let url = dir.appendingPathComponent(name)
            #expect(FileManager.default.fileExists(atPath: url.path))
            let perms = try FileManager.default.attributesOfItem(atPath: url.path)[.posixPermissions] as? NSNumber
            #expect(perms?.int16Value == 0o600)
        }
        let dirPerms = try FileManager.default.attributesOfItem(atPath: dir.path)[.posixPermissions] as? NSNumber
        #expect(dirPerms?.int16Value == 0o700)
    }
}

// MARK: - ZDOTDIRShim integration (ISS-077)
// Spawns a real `zsh --login` over a real PTY with the shim wired in, using a fixture
// "home" whose .zshrc both defines an alias AND clobbers precmd_functions wholesale —
// the exact failure the old timed stdin injection could not survive. Proves the user's
// config loads (alias works) and the OSC 133 prompt marker still appears.

struct ZDOTDIRShimIntegrationTests {

    @Test func shimLoadsUserConfigAndInstallsHooksDespiteClobber() async throws {
        let fixture = FileManager.default.temporaryDirectory
            .appendingPathComponent("sputnik-shim-fixture-\(UUID().uuidString)", isDirectory: true)
        try FileManager.default.createDirectory(at: fixture, withIntermediateDirectories: true)
        defer { try? FileManager.default.removeItem(at: fixture) }

        let zshrc = """
            alias sputnik_marker='echo MARKER_OK'
            precmd_functions=()
            preexec_functions=()
            """
        try Data((zshrc + "\n").utf8).write(to: fixture.appendingPathComponent(".zshrc"))

        let shimDir = try ZDOTDIRShim.install()
        defer { try? FileManager.default.removeItem(at: shimDir) }

        var env = ProcessInfo.processInfo.environment
        env["TERM"] = "xterm-256color"
        env["ZDOTDIR"] = shimDir.path
        env[ZDOTDIRShim.shimDirVar] = shimDir.path
        env[ZDOTDIRShim.userZDOTDIRVar] = fixture.path

        let launched = try PTYSpawn.spawnLoginShell(
            executable: "/bin/zsh", arguments: ["--login"],
            workingDirectory: fixture.path, environment: env)
        let fd = launched.masterFD
        defer {
            kill(launched.pid, SIGKILL)
            var status: Int32 = 0
            waitpid(launched.pid, &status, 0)
            close(fd)
        }

        let accumulator = OutputAccumulator()
        let drain = Task.detached {
            var buffer = [UInt8](repeating: 0, count: 4096)
            while !Task.isCancelled {
                let n = read(fd, &buffer, buffer.count)
                if n <= 0 { break }
                if let text = String(bytes: buffer[0..<n], encoding: .utf8) {
                    await accumulator.append(text)
                }
            }
        }
        defer { drain.cancel() }

        // Let the login shell finish loading, then trigger a command + a fresh prompt.
        try? await Task.sleep(nanoseconds: 1_500_000_000)
        _ = "sputnik_marker\n".withCString { write(fd, $0, strlen($0)) }

        let ok = await withTimeout(seconds: 10) {
            while !Task.isCancelled {
                // MARKER_OK → the user's alias loaded (real .zshrc sourced);
                // ESC]133;A → the precmd hook fired despite the wholesale clobber.
                if await accumulator.contains("MARKER_OK"),
                   await accumulator.contains("\u{1b}]133;A") { return true }
                try? await Task.sleep(nanoseconds: 100_000_000)
            }
            return false
        }
        #expect(ok == true)
    }
}
